import json
import csv
import pandas as pd

FIELD_MAP = {
    "user_id": "user_id", "id": "user_id", "userId": "user_id",
    "email": "email", "email_address": "email",
    "full_name": "name", "name": "name", "userName": "name",
    "registration_date": "created_date", "created_at": "created_date", "joined": "created_date",
    "status": "status",
}


def normalize(record):
    out = {}
    for k, v in record.items():
        if k in FIELD_MAP:
            out[FIELD_MAP[k]] = v
    return out


def load_source_a():
    with open("/data/source_a/users.json") as f:
        data = json.load(f)
    return [normalize(r) for r in data]


def load_source_b():
    rows = []
    with open("/data/source_b/users.csv", newline="") as f:
        for r in csv.DictReader(f):
            rows.append(normalize(r))
    return rows


def load_source_c():
    df = pd.read_parquet("/data/source_c/users.parquet")
    return [normalize(r) for r in df.to_dict("records")]


def to_date(v):
    if v is None:
        return None
    return str(pd.to_datetime(v).date())


def coerce(record):
    out = {}
    if record.get("user_id") is not None:
        out["user_id"] = int(record["user_id"])
    if record.get("name") is not None:
        out["name"] = str(record["name"])
    if record.get("email") is not None:
        out["email"] = str(record["email"])
    if record.get("created_date") is not None:
        out["created_date"] = to_date(record["created_date"])
    if record.get("status") is not None:
        out["status"] = str(record["status"])
    return out


sources = {
    "source_a": [coerce(r) for r in load_source_a()],
    "source_b": [coerce(r) for r in load_source_b()],
    "source_c": [coerce(r) for r in load_source_c()],
}
PRIORITY = ["source_a", "source_b", "source_c"]

# index by user_id per source
by_source = {s: {r["user_id"]: r for r in recs} for s, recs in sources.items()}

all_ids = sorted({uid for s in PRIORITY for uid in by_source[s]})

FIELDS = ["name", "email", "created_date", "status"]

merged = []
conflicts = []
for uid in all_ids:
    present = [s for s in PRIORITY if uid in by_source[s]]
    row = {"user_id": uid}
    for field in FIELDS:
        vals = {}
        for s in present:
            v = by_source[s][uid].get(field)
            if v is not None:
                vals[s] = v
        if not vals:
            continue
        selected = next(vals[s] for s in PRIORITY if s in vals)
        row[field] = selected
        distinct = set(vals.values())
        if len(distinct) > 1:
            conflicts.append({
                "user_id": uid,
                "field": field,
                "values": vals,
                "selected": selected,
            })
    merged.append(row)

out_df = pd.DataFrame(merged, columns=["user_id", "name", "email", "created_date", "status"])
out_df["user_id"] = out_df["user_id"].astype("int64")
for c in ["name", "email", "created_date", "status"]:
    out_df[c] = out_df[c].astype("object")
out_df.to_parquet("/app/merged_users.parquet", index=False)

report = {"total_conflicts": len(conflicts), "conflicts": conflicts}
with open("/app/conflicts.json", "w") as f:
    json.dump(report, f, indent=2)

print(out_df.to_string())
print(json.dumps(report, indent=2))

